import React, { useEffect, useState } from 'react'
import { Link } from 'react-router-dom'
import { supabase } from '../../lib/supabaseClient'
import { IMAGES } from '../../constants/images'

export const BrowseSessions: React.FC = () => {
  const [sessions, setSessions] = useState<any[]>([])
  const [loading, setLoading] = useState(true)
  const [user, setUser] = useState<any>(null)
  const [userProfile, setUserProfile] = useState<any>(null)
  const [participants, setParticipants] = useState<Record<string, number>>({})
  const [joinedSessions, setJoinedSessions] = useState<Set<string>>(new Set())
  const [joiningId, setJoiningId] = useState<string | null>(null)
  const [leavingId, setLeavingId] = useState<string | null>(null)
  const [message, setMessage] = useState<{ text: string; type: 'success' | 'error' | 'info' } | null>(null)

  useEffect(() => {
    loadData()
  }, [])

  const loadData = async () => {
    setLoading(true)
    setMessage(null)

    const { data: { user: currentUser } } = await supabase.auth.getUser()
    setUser(currentUser)

    if (currentUser) {
      const { data: profile } = await supabase
        .from('users')
        .select('*')
        .eq('id', currentUser.id)
        .single()
      setUserProfile(profile)
    }

    const today = new Date().toISOString().split('T')[0]
    const { data: sessionsData, error: sessionsError } = await supabase
      .from('sports_sessions')
      .select('*')
      .gte('session_date', today)
      .order('session_date', { ascending: true })
      .order('session_time', { ascending: true })

    if (sessionsError) {
      console.error('Error loading sessions:', sessionsError)
      setLoading(false)
      return
    }

    setSessions(sessionsData || [])

    if (sessionsData && sessionsData.length > 0) {
      const counts: Record<string, number> = {}
      const joined: Set<string> = new Set()

      for (const session of sessionsData) {
        const { count } = await supabase
          .from('session_participants')
          .select('*', { count: 'exact', head: true })
          .eq('session_id', session.id)
        counts[session.id] = count || 0

        if (currentUser) {
          const { data: joinedData } = await supabase
            .from('session_participants')
            .select('*')
            .eq('session_id', session.id)
            .eq('user_id', currentUser.id)
          if (joinedData && joinedData.length > 0) {
            joined.add(session.id)
          }
        }
      }

      setParticipants(counts)
      setJoinedSessions(joined)
    }

    setLoading(false)
  }

  const handleJoin = async (sessionId: string) => {
    if (!user) {
      setMessage({ text: '⚠️ Please login first', type: 'error' })
      return
    }

    setJoiningId(sessionId)

    const session = sessions.find(s => s.id === sessionId)
    if (!session) {
      setJoiningId(null)
      return
    }

    if (joinedSessions.has(sessionId)) {
      setMessage({ text: '✅ You already joined this session', type: 'info' })
      setJoiningId(null)
      return
    }

    if (session.created_by === user.id) {
      setMessage({ text: '👑 You cannot join your own session', type: 'error' })
      setJoiningId(null)
      return
    }

    const currentCount = participants[sessionId] || 0
    if (currentCount >= session.max_participants) {
      setMessage({ text: '🔴 This session is full!', type: 'error' })
      setJoiningId(null)
      return
    }

    const { error } = await supabase
      .from('session_participants')
      .insert({
        session_id: sessionId,
        user_id: user.id
      })

    if (error) {
      setMessage({ text: '❌ Failed to join: ' + error.message, type: 'error' })
    } else {
      setMessage({ text: '✅ You have joined the session!', type: 'success' })
      await loadData()
    }
    setJoiningId(null)
  }

  const handleLeave = async (sessionId: string) => {
    if (!user) return

    if (!window.confirm('Are you sure you want to leave this session?')) {
      return
    }

    setLeavingId(sessionId)

    const { error } = await supabase
      .from('session_participants')
      .delete()
      .eq('session_id', sessionId)
      .eq('user_id', user.id)

    if (error) {
      setMessage({ text: '❌ Failed to leave: ' + error.message, type: 'error' })
    } else {
      setMessage({ text: '✅ You have left the session', type: 'success' })
      await loadData()
    }
    setLeavingId(null)
  }

  if (loading) {
    return (
      <div style={{
        minHeight: '100vh',
        background: '#0a0a0a',
        color: 'white',
        padding: '40px',
        textAlign: 'center'
      }}>
        Loading sessions...
      </div>
    )
  }

  return (
    <div style={{
      minHeight: '100vh',
      background: `url(${IMAGES.browseSessionsBg}) center/cover no-repeat`,
      backgroundColor: '#0a0a0a',
      color: 'white',
      padding: '24px',
      position: 'relative'
    }}>
      {/* Dark Overlay */}
      <div style={{
        position: 'absolute',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        background: 'rgba(0,0,0,0.65)',
        zIndex: 0
      }} />

      {/* Content */}
      <div style={{
        maxWidth: '900px',
        margin: '0 auto',
        position: 'relative',
        zIndex: 1
      }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
          <div>
            <h1 style={{ color: '#FFD700', fontSize: '28px' }}>📅 Browse Sessions</h1>
            <p style={{ color: '#888' }}>Find and join sports sessions near you</p>
          </div>
          <Link to="/create-session" style={{
            background: '#c8a200',
            color: '#0a0a0a',
            padding: '10px 20px',
            borderRadius: '8px',
            textDecoration: 'none',
            fontWeight: 'bold'
          }}>
            + Create Session
          </Link>
        </div>

        {message && (
          <div style={{
            padding: '12px 16px',
            borderRadius: '8px',
            marginBottom: '16px',
            background: message.type === 'success' ? 'rgba(82,192,122,0.15)' :
                       message.type === 'error' ? 'rgba(255,68,68,0.15)' :
                       'rgba(200,162,0,0.15)',
            border: `1px solid ${
              message.type === 'success' ? '#52c07a' :
              message.type === 'error' ? '#ff4444' :
              '#c8a200'
            }`,
            color: message.type === 'success' ? '#52c07a' :
                   message.type === 'error' ? '#ff4444' :
                   '#c8a200'
          }}>
            {message.text}
          </div>
        )}

        {sessions.length === 0 ? (
          <div style={{
            background: '#0d0d0d',
            border: '1px solid #c8a20020',
            borderRadius: '16px',
            padding: '60px',
            textAlign: 'center',
            color: '#666'
          }}>
            <div style={{ fontSize: '48px', marginBottom: '16px' }}>🏟️</div>
            <h2 style={{ color: '#888' }}>No sessions yet</h2>
            <p>Be the first to create a session!</p>
          </div>
        ) : (
          sessions.map((session) => {
            const isCreator = session.created_by === user?.id
            const currentCount = participants[session.id] || 0
            const isFull = currentCount >= session.max_participants
            const hasJoined = joinedSessions.has(session.id)
            const canJoin = !isCreator && !isFull && !hasJoined
            const isJoining = joiningId === session.id
            const isLeaving = leavingId === session.id
            const availableSpots = session.max_participants - currentCount

            return (
              <div key={session.id} style={{
                background: '#0d0d0d',
                border: `1px solid ${hasJoined ? '#52c07a40' : isFull ? '#ff444430' : '#c8a20020'}`,
                borderRadius: '12px',
                padding: '20px',
                marginBottom: '12px',
                transition: 'all 0.3s'
              }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                  <div style={{ flex: 1 }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px', flexWrap: 'wrap' }}>
                      <h3 style={{ fontSize: '18px', fontWeight: 'bold' }}>{session.sport_type}</h3>
                      {isCreator && (
                        <span style={{
                          background: '#c8a20020',
                          color: '#c8a200',
                          padding: '2px 12px',
                          borderRadius: '20px',
                          fontSize: '11px',
                          fontWeight: 'bold'
                        }}>
                          👑 Creator
                        </span>
                      )}
                      {hasJoined && (
                        <span style={{
                          background: '#52c07a20',
                          color: '#52c07a',
                          padding: '2px 12px',
                          borderRadius: '20px',
                          fontSize: '11px',
                          fontWeight: 'bold'
                        }}>
                          ✅ Joined
                        </span>
                      )}
                      {isFull && !isCreator && (
                        <span style={{
                          background: '#ff444420',
                          color: '#ff4444',
                          padding: '2px 12px',
                          borderRadius: '20px',
                          fontSize: '11px',
                          fontWeight: 'bold'
                        }}>
                          🔴 Full
                        </span>
                      )}
                    </div>

                    <p style={{ color: '#888', fontSize: '14px', marginTop: '6px' }}>
                      📍 {session.location}
                    </p>
                    <p style={{ color: '#666', fontSize: '13px' }}>
                      📅 {session.session_date} at {session.session_time.substring(0, 5)}
                    </p>

                    {session.description && (
                      <p style={{ color: '#666', fontSize: '13px', marginTop: '8px' }}>
                        {session.description}
                      </p>
                    )}

                    <div style={{ display: 'flex', gap: '12px', marginTop: '10px', flexWrap: 'wrap' }}>
                      <span style={{
                        background: '#1a1a1a',
                        padding: '4px 14px',
                        borderRadius: '20px',
                        fontSize: '12px',
                        color: '#888'
                      }}>
                        👥 {currentCount} / {session.max_participants} players
                      </span>
                      {availableSpots > 0 && !isFull && !hasJoined && (
                        <span style={{
                          background: '#1a3a1a',
                          padding: '4px 14px',
                          borderRadius: '20px',
                          fontSize: '12px',
                          color: '#52c07a'
                        }}>
                          {availableSpots} spot{availableSpots > 1 ? 's' : ''} available
                        </span>
                      )}
                      {session.whatsapp_link && (
                        <a 
                          href={session.whatsapp_link} 
                          target="_blank" 
                          rel="noopener noreferrer" 
                          style={{
                            background: '#25D36620',
                            padding: '4px 14px',
                            borderRadius: '20px',
                            fontSize: '12px',
                            color: '#25D366',
                            textDecoration: 'none'
                          }}
                        >
                          💬 WhatsApp Group
                        </a>
                      )}
                    </div>

                    <div style={{
                      width: '100%',
                      height: '4px',
                      background: '#1a1a1a',
                      borderRadius: '2px',
                      marginTop: '12px',
                      overflow: 'hidden'
                    }}>
                      <div style={{
                        width: `${(currentCount / session.max_participants) * 100}%`,
                        height: '100%',
                        background: isFull ? '#ff4444' : 
                                   currentCount / session.max_participants > 0.7 ? '#FFD700' : 
                                   '#52c07a',
                        borderRadius: '2px',
                        transition: 'width 0.3s'
                      }} />
                    </div>
                  </div>

                  <div style={{ marginLeft: '16px', display: 'flex', flexDirection: 'column', gap: '8px', minWidth: '100px' }}>
                    {canJoin ? (
                      <button
                        onClick={() => handleJoin(session.id)}
                        disabled={isJoining}
                        style={{
                          padding: '10px 24px',
                          background: isJoining ? '#666' : '#c8a200',
                          color: isJoining ? '#444' : '#0a0a0a',
                          border: 'none',
                          borderRadius: '8px',
                          fontWeight: 'bold',
                          cursor: isJoining ? 'default' : 'pointer',
                          fontSize: '14px',
                          width: '100%'
                        }}
                      >
                        {isJoining ? '⏳ Joining...' : 'Join'}
                      </button>
                    ) : hasJoined ? (
                      <button
                        onClick={() => handleLeave(session.id)}
                        disabled={isLeaving}
                        style={{
                          padding: '10px 24px',
                          background: isLeaving ? '#666' : 'transparent',
                          color: isLeaving ? '#444' : '#ff4444',
                          border: '1px solid #ff4444',
                          borderRadius: '8px',
                          fontWeight: 'bold',
                          cursor: isLeaving ? 'default' : 'pointer',
                          fontSize: '14px',
                          width: '100%'
                        }}
                      >
                        {isLeaving ? '⏳ Leaving...' : 'Leave'}
                      </button>
                    ) : isCreator ? (
                      <button
                        disabled
                        style={{
                          padding: '10px 24px',
                          background: '#1a1a1a',
                          color: '#444',
                          border: 'none',
                          borderRadius: '8px',
                          fontSize: '14px',
                          cursor: 'not-allowed',
                          width: '100%'
                        }}
                      >
                        Your Session
                      </button>
                    ) : isFull ? (
                      <button
                        disabled
                        style={{
                          padding: '10px 24px',
                          background: '#1a1a1a',
                          color: '#ff444488',
                          border: 'none',
                          borderRadius: '8px',
                          fontSize: '14px',
                          cursor: 'not-allowed',
                          width: '100%'
                        }}
                      >
                        Full
                      </button>
                    ) : null}
                  </div>
                </div>
              </div>
            )
          })
        )}
      </div>
    </div>
  )
}
